package org.umamo.format.webp

import kotlin.io.encoding.Base64
import kotlin.test.Test
import kotlin.test.assertContentEquals
import kotlin.test.assertEquals

/**
 * Validates [WebPReader]'s VP8L lossless decode against golden fixtures.  Each fixture is a tiny VP8L
 * `.webp` (encoded by libwebp via Pillow) plus the RGBA libwebp itself decodes it to; since VP8L is
 * lossless, our decoder must reproduce those exact pixels.  The fixtures span solid color, an RGB
 * gradient (predictor / subtract-green), an alpha gradient, a four-color image (color-indexing), a
 * larger image (LZ77 backward references), and a 64x64 image with two dissimilar halves (multiple
 * Huffman meta-groups / color cache).  Fixtures are embedded base64 so the test is self-contained.
 */
class WebpVp8lDecodeTest {
	/**
	 * Decodes an embedded VP8L fixture and asserts it matches the embedded libwebp-golden RGBA.
	 *
	 * @param Int width           Expected width.
	 * @param Int height          Expected height.
	 * @param String webpBase64   Base64 of the `.webp` bytes.
	 * @param String rgbaBase64   Base64 of the golden RGBA8888 (top-first, straight alpha).
	 */
	private fun assertDecodes(width: Int, height: Int, webpBase64: String, rgbaBase64: String) {
		val webp = Base64.decode(webpBase64)
		val expected = Base64.decode(rgbaBase64)
		val decoded = WebPReader.read(webp)
		assertEquals(width, decoded.width, "width")
		assertEquals(height, decoded.height, "height")
		assertContentEquals(expected, decoded.rgba, "VP8L decode must match libwebp pixel-for-pixel")
	}

	@Test
	fun decodesSolid() {
		assertDecodes(
			width = 4,
			height = 4,
			webpBase64 = "UklGRh4AAABXRUJQVlA4TBEAAAAvA8AAAAdQsiJXpv+BiOh/AAA=",
			rgbaBase64 = "yGQy/8hkMv/IZDL/yGQy/8hkMv/IZDL/yGQy/8hkMv/IZDL/yGQy/8hkMv/IZDL/yGQy/8hkMv/IZDL/yGQy/w==",
		)
	}

	@Test
	fun decodesGradient() {
		assertDecodes(
			width = 8,
			height = 8,
			webpBase64 = "UklGRiwAAABXRUJQVlA4TCAAAAAvB8ABALmM6H/sClGIgvc/ICQgTPF/p+bAgERMANjeAA==",
			rgbaBase64 = "",
		)
	}

	@Test
	fun decodesAlpha() {
		assertDecodes(
			width = 8,
			height = 8,
			webpBase64 = "UklGRjgAAABXRUJQVlA4TCwAAAAvB8ABELkyRPQ/dhHR/wBhtlEhzp92ryMQCCT5s+7w4AkEUtgmT4An9wD9Bw==",
			rgbaBase64 = "",
		)
	}

	@Test
	fun decodesFewcolors() {
		assertDecodes(
			width = 16,
			height = 16,
			webpBase64 = "UklGRkAAAABXRUJQVlA4TDQAAAAvD8ADAB8gECD4n3VgQyCQ5G87wQIBgv9ZB+Y/8MlRAWG20SQnOcn7HUNE/yPZl/VZ/iUf",
			rgbaBase64 = "",
		)
	}

	@Test
	fun decodesLarger() {
		assertDecodes(
			width = 20,
			height = 20,
			webpBase64 = "UklGRlIAAABXRUJQVlA4TEYAAAAvE8AEELkyRPQ/BmLBZP7Q3SHUP/ofwTOgadtIJnD8IX/GH6tZUNS2DRxU3m03BNfwT8BkeQjKL4AUNEbBW7E3Gi9AGGAb",
			rgbaBase64 = "",
		)
	}

	@Test
	fun decodesComplex() {
		assertDecodes(
			width = 64,
			height = 64,
			webpBase64 = "",
			rgbaBase64 = "",
		)
	}
}
